def evaluate(expr):
    def calc(ops, vals):
        b, a = vals.pop(), vals.pop()
        op = ops.pop()
        if op == '+': vals.append(a + b)
        elif op == '-': vals.append(a - b)
        elif op == '*': vals.append(a * b)
        elif op == '/': vals.append(int(a / b))
    prec = {'+': 1, '-': 1, '*': 2, '/': 2}
    ops, vals = [], []
    i = 0
    while i < len(expr):
        if expr[i].isdigit():
            j = i
            while j < len(expr) and expr[j].isdigit():
                j += 1
            vals.append(int(expr[i:j]))
            i = j
        elif expr[i] == '(':
            ops.append('(')
            i += 1
        elif expr[i] == ')':
            while ops[-1] != '(':
                calc(ops, vals)
            ops.pop()
            i += 1
        elif expr[i] in prec:
            while ops and ops[-1] != '(' and prec.get(ops[-1], 0) >= prec[expr[i]]:
                calc(ops, vals)
            ops.append(expr[i])
            i += 1
        else:
            i += 1
    while ops:
        calc(ops, vals)
    return vals[0]

def parse_csv(text):
    rows, row, field = [], [], []
    in_quotes = False
    i = 0
    while i < len(text):
        ch = text[i]
        if in_quotes:
            if ch == '"' and i + 1 < len(text) and text[i + 1] == '"':
                field.append('"')
                i += 2
                continue
            elif ch == '"':
                in_quotes = False
            else:
                field.append(ch)
        else:
            if ch == '"':
                in_quotes = True
            elif ch == ',':
                row.append(''.join(field))
                field = []
            elif ch == '\n':
                row.append(''.join(field))
                rows.append(row)
                row, field = [], []
            else:
                field.append(ch)
        i += 1
    row.append(''.join(field))
    if row:
        rows.append(row)
    return rows

def is_match(s, p):
    memo = {}
    def dp(i, j):
        if (i, j) in memo:
            return memo[(i, j)]
        if j == len(p):
            ans = i == len(s)
        elif j + 1 < len(p) and p[j + 1] == '*':
            ans = dp(i, j + 2)  # skip *
            if i < len(s) and (p[j] == '.' or p[j] == s[i]):
                ans = ans or dp(i + 1, j)  # use *
        elif i < len(s) and (p[j] == '.' or p[j] == s[i]):
            ans = dp(i + 1, j + 1)
        else:
            ans = False
        memo[(i, j)] = ans
        return ans
    return dp(0, 0)

