class TTLStore:
    def __init__(self):
        self.store = {}
        self.expiry_heap = []

    def put(self, key, value, ttl_seconds):
        expire_at = time.time() + ttl_seconds
        self.store[key] = (value, expire_at)
        heapq.heappush(self.expiry_heap, (expire_at, key))

    def get(self, key):
        self._cleanup()
        if key in self.store:
            val, exp = self.store[key]
            if time.time() < exp:
                return val
            del self.store[key]
        return None

    def _cleanup(self):
        now = time.time()
        while self.expiry_heap and self.expiry_heap[0][0] <= now:
            exp, key = heapq.heappop(self.expiry_heap)
            if key in self.store and self.store[key][1] <= now:
                del self.store[key]

def edit_distance(s1, s2):
    m, n = len(s1), len(s2)
    dp = [[0] * (n + 1) for _ in range(m + 1)]
    for i in range(m + 1):
        dp[i][0] = i
    for j in range(n + 1):
        dp[0][j] = j
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i-1] == s2[j-1]:
                dp[i][j] = dp[i-1][j-1]
            else:
                dp[i][j] = 1 + min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1])
    return dp[m][n]

def json_path(data, path):
    keys = path.split('.')
    current = data
    for key in keys:
        if not key:
            continue
        if key.startswith('[') and key.endswith(']'):
            idx = int(key[1:-1])
            if isinstance(current, list) and 0 <= idx < len(current):
                current = current[idx]
            else:
                return None
        elif isinstance(current, dict) and key in current:
            current = current[key]
        elif isinstance(current, list):
            try:
                current = current[int(key)]
            except (ValueError, IndexError):
                return None
        else:
            return None
    return current

class AVLNode:
    def __init__(self, key):
        self.key = key
        self.left = self.right = None
        self.height = 1

def height(node):
    return node.height if node else 0

def rotate_right(y):
    x = y.left
    y.left = x.right
    x.right = y
    y.height = 1 + max(height(y.left), height(y.right))
    x.height = 1 + max(height(x.left), height(x.right))
    return x

def rotate_left(x):
    y = x.right
    x.right = y.left
    y.left = x
    x.height = 1 + max(height(x.left), height(x.right))
    y.height = 1 + max(height(y.left), height(y.right))
    return y

def avl_insert(root, key):
    if not root:
        return AVLNode(key)
    if key < root.key:
        root.left = avl_insert(root.left, key)
    else:
        root.right = avl_insert(root.right, key)
    root.height = 1 + max(height(root.left), height(root.right))
    balance = height(root.left) - height(root.right)
    if balance > 1 and key < root.left.key:
        return rotate_right(root)
    if balance < -1 and key > root.right.key:
        return rotate_left(root)
    if balance > 1 and key > root.left.key:
        root.left = rotate_left(root.left)
        return rotate_right(root)
    if balance < -1 and key < root.right.key:
        root.right = rotate_right(root.right)
        return rotate_left(root)
    return root

class FileSystem:
    def __init__(self):
        self.root = {}
        self.cwd = self.root
        self.path_stack = []

    def _resolve(self, path):
        if path.startswith('/'):
            node = self.root
            parts = [p for p in path.split('/') if p and p != '.']
        else:
            node = self.cwd
            parts = [p for p in path.split('/') if p and p != '.']
        for part in parts:
            if part == '..':
                return None  # simplified
            if part not in node:
                return None
            node = node[part]
        return node

    def mkdir(self, path):
        parts = [p for p in path.split('/') if p]
        node = self.root if path.startswith('/') else self.cwd
        for part in parts:
            if part not in node:
                node[part] = {}
            node = node[part]

    def ls(self, path='.'):
        node = self._resolve(path) if path != '.' else self.cwd
        return sorted(node.keys()) if node is not None else []

    def cd(self, path):
        target = self._resolve(path)
        if target is not None:
            self.cwd = target

def parse_http_request(raw):
    parts = raw.split('\r\n\r\n', 1)
    header_section = parts[0]
    body = parts[1] if len(parts) > 1 else ''
    lines = header_section.split('\r\n')
    request_line = lines[0].split(' ')
    method = request_line[0]
    path = request_line[1] if len(request_line) > 1 else '/'
    version = request_line[2] if len(request_line) > 2 else 'HTTP/1.1'
    headers = {}
    for line in lines[1:]:
        if ':' in line:
            key, val = line.split(':', 1)
            headers[key.strip()] = val.strip()
    return {'method': method, 'path': path, 'version': version,
            'headers': headers, 'body': body}

