from functools import wraps

def lru_cache(capacity):
    def decorator(func):
        cache = OrderedDict()
        @wraps(func)
        def wrapper(*args):
            if args in cache:
                cache.move_to_end(args)
                return cache[args]
            result = func(*args)
            cache[args] = result
            if len(cache) > capacity:
                cache.popitem(last=False)
            return result
        wrapper.cache = cache
        return wrapper
    return decorator

import threading

def parallel_merge_sort(arr, threshold=1000):
    if len(arr) <= 1:
        return arr
    if len(arr) <= threshold:
        return sorted(arr)
    mid = len(arr) // 2
    left_result = [None]
    right_result = [None]
    def sort_left():
        left_result[0] = parallel_merge_sort(arr[:mid], threshold)
    def sort_right():
        right_result[0] = parallel_merge_sort(arr[mid:], threshold)
    t1 = threading.Thread(target=sort_left)
    t2 = threading.Thread(target=sort_right)
    t1.start(); t2.start()
    t1.join(); t2.join()
    left, right = left_result[0], right_result[0]
    result = []
    i = j = 0
    while i < len(left) and j < len(right):
        if left[i] <= right[j]:
            result.append(left[i]); i += 1
        else:
            result.append(right[j]); j += 1
    result.extend(left[i:])
    result.extend(right[j:])
    return result

import hashlib

class BloomFilter:
    def __init__(self, size, num_hashes):
        self.size = size
        self.num_hashes = num_hashes
        self.bits = [False] * size

    def _hashes(self, item):
        results = []
        for i in range(self.num_hashes):
            h = hashlib.sha256(f"{item}:{i}".encode()).hexdigest()
            results.append(int(h, 16) % self.size)
        return results

    def add(self, item):
        for idx in self._hashes(item):
            self.bits[idx] = True

    def might_contain(self, item):
        return all(self.bits[idx] for idx in self._hashes(item))

class UndoRedoManager:
    def __init__(self):
        self.undo_stack = []
        self.redo_stack = []

    def execute(self, command):
        command.execute()
        self.undo_stack.append(command)
        self.redo_stack.clear()

    def undo(self):
        if not self.undo_stack:
            return
        cmd = self.undo_stack.pop()
        cmd.undo()
        self.redo_stack.append(cmd)

    def redo(self):
        if not self.redo_stack:
            return
        cmd = self.redo_stack.pop()
        cmd.execute()
        self.undo_stack.append(cmd)

class SetValueCommand:
    def __init__(self, obj, attr, new_val):
        self.obj = obj
        self.attr = attr
        self.new_val = new_val
        self.old_val = None

    def execute(self):
        self.old_val = getattr(self.obj, self.attr)
        setattr(self.obj, self.attr, self.new_val)

    def undo(self):
        setattr(self.obj, self.attr, self.old_val)

def validate(data, schema, path=''):
    errors = []
    if schema.get('type') == 'object':
        if not isinstance(data, dict):
            return [f"{path}: expected object, got {type(data).__name__}"]
        for key, sub_schema in schema.get('properties', {}).items():
            if key not in data:
                if sub_schema.get('required', False):
                    errors.append(f"{path}.{key}: missing required field")
            else:
                errors.extend(validate(data[key], sub_schema, f"{path}.{key}"))
    elif schema.get('type') == 'array':
        if not isinstance(data, list):
            return [f"{path}: expected array, got {type(data).__name__}"]
        item_schema = schema.get('items', {})
        for i, item in enumerate(data):
            errors.extend(validate(item, item_schema, f"{path}[{i}]"))
    elif schema.get('type') == 'string':
        if not isinstance(data, str):
            errors.append(f"{path}: expected string, got {type(data).__name__}")
    elif schema.get('type') == 'number':
        if not isinstance(data, (int, float)):
            errors.append(f"{path}: expected number, got {type(data).__name__}")
    return errors

from collections import defaultdict

class EventEmitter:
    def __init__(self):
        self.listeners = defaultdict(list)

    def on(self, event, callback):
        self.listeners[event].append(callback)
        return self

    def off(self, event, callback):
        if event in self.listeners:
            self.listeners[event] = [
                cb for cb in self.listeners[event] if cb != callback
            ]
        return self

    def emit(self, event, *args, **kwargs):
        for callback in self.listeners.get(event, []):
            callback(*args, **kwargs)
        return self

    def once(self, event, callback):
        def wrapper(*args, **kwargs):
            callback(*args, **kwargs)
            self.off(event, wrapper)
        self.on(event, wrapper)
        return self
